#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N], B[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &B[i]);
        }
        int count = 0;
        int time = 0;
        for (int i = 0; i < N; i++) {
            if (time + B[i] <= A[i]) {
                count++;
                time = A[i];
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

