import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            int[] B = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                B[i] = sc.nextInt();
            }
            int count = 0;
            int time = 0;
            for (int i = 0; i < N; i++) {
                if (time + B[i] <= A[i]) {
                    count++;
                    time = A[i];
                }
            }
            System.out.println(count);
        }
    }
}

